output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT(COUNT(DISTINCT ?player) AS ?count) WHERE {
  ?player wdt:P2048 ?runs .
  FILTER(xsd:int(?runs) >= 10000)
}

